INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "", 0, 0, 15, 0, 30000, 35, 2, "", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "", 0, 0, 1, 0, 40000, 36, 8, "", 100);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪", 1, 0, 1, 107501, 40001, 37, 8, "ぺコリーヌ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪", 1, 0, 2, 107601, 40001, 38, 8, "コッコロ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪", 1, 0, 3, 107801, 40001, 39, 8, "キャル", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！", 1, 0, 4, 107701, 40001, 40, 8, "スズメ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪", 1, 0, 5, 107901, 40001, 41, 8, "タマキ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪", 2, 0, 6, 107501, 40001, 42, 8, "ぺコリーヌ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ", 2, 0, 7, 107601, 40001, 43, 8, "コッコロ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！", 2, 0, 8, 107801, 40001, 44, 8, "キャル", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪", 2, 0, 9, 107701, 40001, 45, 8, "スズメ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？", 2, 0, 10, 107901, 40001, 46, 8, "タマキ", 150);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "", 0, 0, 1, 0, 40003, 57, 8, "", 150);
