INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (23001, "", 0, 0, 10, 0, 20001, 320, 2, "", 20);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 0, 1, 125801, 40011, 321, 2, "リリ", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, 0, 2, 126001, 40011, 322, 2, "クリア", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "んーと。\nこれ、あげる。\nはい", 1, 0, 3, 126101, 40011, 323, 2, "プレシア", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 0, 4, 125801, 40011, 324, 2, "リリ", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 0, 5, 126001, 40011, 325, 2, "クリア", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (24001, "お兄。\nきてくれて、うれしい", 2, 0, 6, 126101, 40011, 326, 2, "プレシア", 1);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (91002, "", 0, 532001, 1, 0, 80009, 327, 8, "", 100);
